+func expandLocalCandidates(seeds []searchCandidate, symbolsByFile map[string][]SymbolRecord, read contentReader, languages map[string]string, options SearchOptions) []searchCandidate {
+	if options.TopK <= defaultSearchTopK || len(seeds) == 0 {
+		return nil
+	}
+	existing := make(map[string]bool, len(seeds))
+	for _, candidate := range seeds {
+		if candidate.result.SymbolID != "" {
+			existing[candidate.result.SymbolID] = true
+		}
+	}
+	expanded := make(map[string]searchCandidate)
+	seededFiles := make(map[string]bool, deepSearchLocalSeedFiles)
+	contentCache := make(map[string][]string)
+	for _, seed := range seeds {
+		filePath := seed.result.FilePath
+		if seed.result.SymbolID == "" || seededFiles[filePath] {
+			continue
+		}
+		if len(seededFiles) == deepSearchLocalSeedFiles {
+			break
+		}
+		symbols := symbolsByFile[filePath]
+		seedIndex := -1
+		for index := range symbols {
+			if symbols[index].ID == seed.result.SymbolID {
+				seedIndex = index
+				break
+			}
+		}
+		if seedIndex < 0 {
+			continue
+		}
+		lines, ok := contentCache[filePath]
+		if !ok {
+			content, readable := read(filePath)
+			if !readable {
+				continue
+			}
+			lines = strings.Split(content, "\n")
+			contentCache[filePath] = lines
+		}
+		seededFiles[filePath] = true
+		added := 0
+		for distance := 1; added < deepSearchLocalNeighbors && (seedIndex-distance >= 0 || seedIndex+distance < len(symbols)); distance++ {
+			for _, index := range []int{seedIndex - distance, seedIndex + distance} {
+				if index < 0 || index >= len(symbols) {
+					continue
+				}
+				symbol := symbols[index]
+				if existing[symbol.ID] || expanded[symbol.ID].result.SymbolID != "" {
+					continue
+				}
+				start, end := clampRegion(symbol.StartLine, symbol.EndLine, len(lines))
+				if start == 0 {
+					continue
+				}
+				if end-start+1 > options.MaxRegionLines {
+					end = minInt(len(lines), start+options.MaxRegionLines-1)
+				}
+				snippetStart, snippetEnd := focusedSnippetRegion(start, end, start, options.MaxSnippetLines)
+				score := 0.24*seed.score + 0.25/float64(distance)
+				expanded[symbol.ID] = searchCandidate{
+					result: SearchResult{
+						FilePath: filePath, StartLine: start, EndLine: end, FocusLine: start,
+						SnippetStartLine: snippetStart, SnippetEndLine: snippetEnd,
+						Language: languages[filePath], Kind: symbol.Kind, SymbolID: symbol.ID,
+						SymbolName: symbol.Name, QualifiedName: symbol.QualifiedName,
+						Signature: symbol.Signature, Signals: []string{"local-neighbor"},
+						Snippet: strings.Join(lines[snippetStart-1:snippetEnd], "\n"),
+					},
+					baseScore: score,
+					score:     score,
+				}
+				added++
+				if added == deepSearchLocalNeighbors {
+					break
+				}
+			}
+		}
+	}
+	out := make([]searchCandidate, 0, len(expanded))
+	for _, candidate := range expanded {
+		out = append(out, candidate)
+	}
+	sortSearchCandidates(out)
+	return out
+}

